const defaultFeatures = [
  { title: 'Garantie Décennale', description: 'Couvre les dommages qui compromettent la solidité ou l\'habitabilité de l\'ouvrage pendant 10 ans après réception des travaux.', icon: '🛡' },
  { title: 'RC Pro Électricien', description: 'Responsabilité Civile Professionnelle couvrant les dommages causés aux tiers lors de votre activité.', icon: '⚖' },
  { title: 'Travaux Électriques', description: 'Installation électrique, câblage, tableau électrique, prises, interrupteurs et éclairage.', icon: '⚡' },
  { title: 'Domotique', description: 'Systèmes domotiques, domotique connectée, éclairage intelligent et gestion énergétique.', icon: '🏠' },
  { title: 'IRVE', description: 'Infrastructure de Recharge pour Véhicules Électriques. Installation de bornes de recharge.', icon: '🔌' },
  { title: 'Assistance 24h/24', description: 'Soutien juridique et assistance en cas de sinistre, où que vous soyez en France.', icon: '📞' }
];

export default function Features({ section }) {
  const features = section?.cards?.length > 0 
    ? section.cards.map(card => ({
        title: card.title,
        description: card.description || card.content,
        icon: card.icon || '⚡'
      }))
    : defaultFeatures;

  return (
    <section id="features" className="py-12 md:py-20 bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-10 md:mb-14">
          <h2 className="text-2xl sm:text-3xl md:text-4xl font-bold text-gray-900">
            {section?.title || 'Nos'} <span className="text-yellow-600">garanties</span> completes
          </h2>
          {section?.subtitle && (
            <p className="mt-3 sm:mt-4 text-gray-600 text-base md:text-lg max-w-2xl mx-auto">
              {section.subtitle}
            </p>
          )}
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6">
          {features.map((feature, index) => (
            <div key={index} className="bg-white rounded-2xl p-5 sm:p-6 shadow-md hover:shadow-xl transition-shadow">
              <div className="flex items-start gap-3 sm:gap-4">
                <div className="w-10 h-10 sm:w-12 sm:h-12 bg-yellow-100 rounded-xl flex items-center justify-center flex-shrink-0">
                  <span className="text-xl sm:text-2xl">{feature.icon}</span>
                </div>
                <div>
                  <h3 className="text-base sm:text-lg font-bold text-gray-900 mb-1.5 sm:mb-2">{feature.title}</h3>
                  <p className="text-gray-600 text-sm">{feature.description}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
